\label{constr:nc-single}

	\begin{enumerate}
		\item 	
		Associate a quiver $Q$ to $\mathrm{CF}^1(\mathbb{L})$. Namely, each component of (the domain of) $\mathbb{L}$ is associated with a vertex, and each generator in $\mathrm{CF}^1(\mathbb{L})$ is associated with an arrow.
		\item 
		Extend the Fukaya algebra $A$ of $\mathbb{L}$ over the path algebra $\Lambda Q$ and obtain a non-commutative $A_\infty-$algebra $$\tilde{A}^\mathbb{L} = \Lambda Q\otimes_{\Lambda^\oplus} \mathrm{CF}(\mathbb{L}),$$ 
		whose unit is $1_{\mathbb{L}} = \sum 1_{L_i}$.  $\Lambda^\oplus \subset \Lambda Q$ denotes $\bigoplus_i \Lambda \cdot e_i$ where $e_i$ are the trivial paths at vertices of $Q$.  The fibered tensor product means that an element $a \otimes X$ is non-zero only when tail of $a$ corresponds to the source of $X$.  The $A_\infty$ operations are defined by
		\begin{equation} \label{eq:mk}
			m_k (f_1 X_1,\ldots,f_k X_k) := f_k \ldots f_1 \, m_k (X_1,\ldots,X_k)
		\end{equation}
		where $X_l \in \mathrm{CF}(\mathbb{L})$  and $f_l \in \Lambda Q$.
		\item Extend the formalism of bounding cochains of \cite{FOOO} over $\Lambda Q$.  Namely, we take 
		\begin{equation} \label{eq:b}
			b = \sum_l b_l B_l
		\end{equation}
		where $B_l$ are the generators of $\mathrm{CF}^1(\mathbb{L})$, and $b_l$ are the corresponding arrows in $Q$.  Then define the deformed $A_\infty$ structure $m_k^{b}$ as in \cite{FOOO} and via Equation \eqref{eq:mk}.
		\item Quotient out the quiver algebra by the two-sided ideal $R$ generated by coefficients of the obstruction term $m_0^b$, so that $m_0^b = W\cdot 1_\mathbb{L}$ over 
		$$\mathbb{A} := \Lambda Q/R.$$  $\mathbb{A}$ is called the noncommutative space of weakly unobstructed deformations of $\mathbb{L}$.
		We call $(\mathbb{A},W)$ to be a noncommutative localized mirror of $X$ probed by $\mathbb{L}$.
		\item Extend the Fukaya category over $\mathbb{A}$, and enlarge the Fukaya category by including the objects $(\mathbb{L},b)$ where $b$ in \eqref{eq:b} is now defined over $\mathbb{A}$. We call $(\mathbb{L},b)$ a noncommutative family of Lagrangians parameterized by $\mathbb{A}$.  This means for $L_1,L_2$ in the original Fukaya category, the morphism space is now extended as $\mathbb{A} \otimes \mathrm{CF}(L_1,L_2)$.  The morphism spaces between $(\mathbb{L},b)$ and $L$ are enlarged to be $\mathrm{CF}((\mathbb{L},b),L) := \mathbb{A}\otimes_{\Lambda^\oplus} \mathrm{CF}(\mathbb{L},L)$ (and similarly for $\mathrm{CF}(L,(\mathbb{L},b))$).  We already have $\mathrm{CF}((\mathbb{L},b),(\mathbb{L},b))$ in Step 2 (except that $\Lambda Q$ is replaced by $\mathbb{A}$).  The $m_k$ operations are extended in a similar way to \eqref{eq:mk}.
	\end{enumerate}

